VALUES
  ('social-worker-moex-06650', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作管理議題中，某些事件可能影響組織目標之達成，風險管理即是為有效管理可能發生事件之不 利影響。其中政府因應莫拉克颱風，推動培力就業計畫，是因應何種社會風險？', '["科技層面的社會風險", "教育層面的社會風險", "政治層面的社會風險", "經濟層面的社會風險"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06651', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作管理者應有風險管理的概念，風險管理有幾個重要關鍵觀念，其中使用一套有系統的程序，進 行廣泛的搜集，以發掘可能發生風險之事件及其發生之原因和方式，此概念稱之為何？', '["風險評估", "風險辨識", "風險分析", "風險處理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06652', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '災難事件的發生經常需要社會工作者的積極投入，根據國際災害研究的發現及災害服務組織的經驗總結 ，災害週期可區分為四個階段，即預防期、整備期、應變期及重建期，下列何者不屬於預防期應該有的 行動？', '["進行災難風險分析", "建立災難現場指揮系統", "災難管理政策之規劃", "推動防災教育"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06653', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '當社會福利機構中的員工因推動服務而彼此產生衝突，督導的任務即在促使員工間能夠化解衝突，此類 督導之功能為何？', '["支持性功能", "教育性功能", "調解性功能", "行政性功能"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06654', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關社會工作督導的觀點，可能因實務型態或環境的不同，而適用於不同的受督導者。其中較常出現於 社工員係由非社工相關專業背景的管理者所督導的情境，關注績效監督及極大化組織的利益，此為何種 督導觀點？', '["發展督導觀點", "管理主義督導觀點", "優勢督導觀點", "傳統督導觀點"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06655', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '方案評估的取向著重以評估結果做為協助決策者決定是否繼續執行某方案或政策的參考依據，其重點聚 焦在方案的產出與成效上，並分析方案或政策的效益與成本，此類型的評估為何種？', '["經濟性評估", "過程評估", "總結性評估", "多途徑評估"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06656', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作方案規劃中，有關人力的輸入有賴不同專業與相關工作人員團隊的組成與投入，下列敘述何者 屬於多元專業團隊服務（Multidisciplinary Team）的人員組合？', '["由一組包含教育、醫療、社工組成的成員，分別執行不同的任務，彼此不相隸屬", "由一組各自獨立且執行不同任務的人員組成，經彼此的力量的整合，擴大家庭及案主的利益", "一組以強調合作方式執行任務的人員，不只分享資訊，也分擔彼此工作角色", "由一組來自相同的專業合作人員組織，提供相似的服務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06657', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '成效評量是指透過一系列的過程，了解接受方案服務者在各種層面上的改變。下列那一個步驟是規劃與 執行成效評量的正確程序？', '["構思如何蒐集資料—確認指標—撰寫成效評量報告—發展成效評量的邏輯模式", "確認指標—發展成效評量的邏輯模式—構思如何蒐集資料—撰寫成效評量報告", "發展成效評量的邏輯模式—確認指標—構思如何蒐集資料—撰寫成效評量報告", "發展成效評量的邏輯模式—構思如何蒐集資料—確認指標—撰寫成效評量報告"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06658', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '根據志願服務法之規定，志願服務運用者應依志願服務計畫運用志願服務人員，請問下列何者不是志願 服務計畫之內容？', '["升遷", "召募", "輔導", "考核"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:35+00:00", "source_pdf_sha1": "a12893ef6870", "answer_pdf_sha1": "22bc351d55b3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
